import java.util.*;
public class HeapBasics {
    public static void main(String[] a){
        PriorityQueue<Integer> minH=new PriorityQueue<>();
        minH.offer(5);minH.offer(1);minH.offer(3);minH.offer(2);minH.offer(4);
        System.out.println("Min-heap poll order: ");
        while(!minH.isEmpty())System.out.print(minH.poll()+" "); System.out.println();
        PriorityQueue<Integer> maxH=new PriorityQueue<>(Collections.reverseOrder());
        maxH.offer(5);maxH.offer(1);maxH.offer(3);
        System.out.println("Max-heap top: "+maxH.peek());
        System.out.println("offer O(log n), poll O(log n), peek O(1)");
    }
}

import java.util.*;
public class KthLargest {
    public static int findKthLargest(int[] nums, int k){
        PriorityQueue<Integer> minH=new PriorityQueue<>();
        for(int n:nums){minH.offer(n);if(minH.size()>k)minH.poll();}
        return minH.peek();
    }
    public static void main(String[] a){
        System.out.println(findKthLargest(new int[]{3,2,1,5,6,4},2));  // 5
        System.out.println(findKthLargest(new int[]{3,2,3,1,2,4,5,5,6},4)); // 4
        System.out.println("O(n log k) — min-heap size k; top = kth largest");
    }
}

import java.util.*;
public class HeapSort {
    static void heapify(int[] a, int n, int i){
        int largest=i,l=2*i+1,r=2*i+2;
        if(l<n&&a[l]>a[largest])largest=l;
        if(r<n&&a[r]>a[largest])largest=r;
        if(largest!=i){int t=a[i];a[i]=a[largest];a[largest]=t;heapify(a,n,largest);}
    }
    static void heapSort(int[] a){
        int n=a.length;
        for(int i=n/2-1;i>=0;i--)heapify(a,n,i); // build max-heap O(n)
        for(int i=n-1;i>0;i--){int t=a[0];a[0]=a[i];a[i]=t;heapify(a,i,0);} // extract
    }
    public static void main(String[] a){
        int[] arr={64,34,25,12,22,11,90};heapSort(arr);
        System.out.println(Arrays.toString(arr));
        System.out.println("O(n log n) O(1) space — build max-heap then extract n times");
    }
}

import java.util.*;
public class TopKFreq {
    public static int[] topKFrequent(int[] nums, int k){
        Map<Integer,Integer> freq=new HashMap<>();
        for(int n:nums)freq.merge(n,1,Integer::sum);
        PriorityQueue<Integer> pq=new PriorityQueue<>(Comparator.comparingInt(freq::get));
        for(int n:freq.keySet()){pq.offer(n);if(pq.size()>k)pq.poll();}
        int[] res=new int[k];for(int i=k-1;i>=0;i--)res[i]=pq.poll();
        return res;
    }
    public static void main(String[] a){
        System.out.println(Arrays.toString(topKFrequent(new int[]{1,1,1,2,2,3},2)));
        System.out.println(Arrays.toString(topKFrequent(new int[]{1},1)));
        System.out.println("O(n log k) — freq map + min-heap size k on frequency");
    }
}

import java.util.*;
public class KClosest {
    public static int[][] kClosest(int[][] pts, int k){
        PriorityQueue<int[]> maxH=new PriorityQueue<>((a,b)->b[0]*b[0]+b[1]*b[1]-a[0]*a[0]-a[1]*a[1]);
        for(int[] p:pts){maxH.offer(p);if(maxH.size()>k)maxH.poll();}
        return maxH.toArray(new int[0][]);
    }
    public static void main(String[] a){
        int[][] pts={{1,3},{-2,2}};int k=1;
        System.out.println(Arrays.deepToString(kClosest(pts,k)));
        System.out.println("Max-heap size k on distance². Evict farthest. O(n log k)");
    }
}

import java.util.*;
public class LastStone {
    public static int lastStoneWeight(int[] stones){
        PriorityQueue<Integer> maxH=new PriorityQueue<>(Collections.reverseOrder());
        for(int s:stones)maxH.offer(s);
        while(maxH.size()>1){int a=maxH.poll(),b=maxH.poll();if(a!=b)maxH.offer(a-b);}
        return maxH.isEmpty()?0:maxH.poll();
    }
    public static void main(String[] a){
        System.out.println(lastStoneWeight(new int[]{2,7,4,1,8,1})); // 1
        System.out.println(lastStoneWeight(new int[]{1}));             // 1
        System.out.println("Max-heap simulation: always smash two heaviest");
    }
}

import java.util.*;
public class MedianStream {
    static PriorityQueue<Integer> lo=new PriorityQueue<>(Collections.reverseOrder()); // max-heap lower half
    static PriorityQueue<Integer> hi=new PriorityQueue<>(); // min-heap upper half
    static void addNum(int n){
        lo.offer(n);hi.offer(lo.poll());
        if(hi.size()>lo.size())lo.offer(hi.poll());}
    static double findMedian(){return lo.size()>hi.size()?lo.peek():(lo.peek()+hi.peek())/2.0;}
    public static void main(String[] a){
        lo=new PriorityQueue<>(Collections.reverseOrder());hi=new PriorityQueue<>();
        addNum(1);addNum(2);System.out.println(findMedian()); // 1.5
        addNum(3);System.out.println(findMedian()); // 2.0
        System.out.println("Two heaps: max-heap(lower) + min-heap(upper). Balance: |lo|-|hi|<=1");
    }
}

import java.util.*;
public class MeetingRooms2 {
    public static int minMeetingRooms(int[][] intervals){
        Arrays.sort(intervals,(a,b)->a[0]-b[0]);
        PriorityQueue<Integer> endTimes=new PriorityQueue<>();
        for(int[] iv:intervals){
            if(!endTimes.isEmpty()&&endTimes.peek()<=iv[0])endTimes.poll();
            endTimes.offer(iv[1]);}
        return endTimes.size();
    }
    public static void main(String[] a){
        System.out.println(minMeetingRooms(new int[][]{{0,30},{5,10},{15,20}})); // 2
        System.out.println(minMeetingRooms(new int[][]{{7,10},{2,4}}));          // 1
        System.out.println("Sort by start; min-heap of end times; size = rooms needed");
    }
}

import java.util.*;
public class TaskSched {
    public static int leastInterval(char[] tasks, int n){
        int[] cnt=new int[26];for(char t:tasks)cnt[t-'A']++;
        int maxCnt=0;for(int c:cnt)maxCnt=Math.max(maxCnt,c);
        int maxTasksWithMaxCnt=0;for(int c:cnt)if(c==maxCnt)maxTasksWithMaxCnt++;
        int slots=(maxCnt-1)*(n+1)+maxTasksWithMaxCnt;
        return Math.max(slots,tasks.length);
    }
    public static void main(String[] a){
        System.out.println(leastInterval(new char[]{'A','A','A','B','B','B'},2)); // 8
        System.out.println(leastInterval(new char[]{'A','A','A','B','B','B'},0)); // 6
        System.out.println("Formula: (maxCount-1)*(n+1)+maxTasksWithMaxCount. max with tasks.length.");
    }
}

import java.util.*;
public class KthMatrix {
    public static int kthSmallest(int[][] matrix, int k){
        int n=matrix.length;
        PriorityQueue<int[]> pq=new PriorityQueue<>((a,b)->a[0]-b[0]);
        for(int i=0;i<n;i++)pq.offer(new int[]{matrix[i][0],i,0});
        int res=0;
        for(int i=0;i<k;i++){int[] top=pq.poll();res=top[0];int r=top[1],c=top[2];if(c+1<n)pq.offer(new int[]{matrix[r][c+1],r,c+1});}
        return res;
    }
    public static void main(String[] a){
        int[][] m={{1,5,9},{10,11,13},{12,13,15}};
        System.out.println(kthSmallest(m,8)); // 13
        System.out.println(kthSmallest(m,1)); // 1
        System.out.println("O(k log n) — min-heap of (val,row,col); push right neighbor on extract");
    }
}

import java.util.*;
public class HeapSynth {
    static int kthLargest(int[] nums,int k){PriorityQueue<Integer> pq=new PriorityQueue<>();for(int n:nums){pq.offer(n);if(pq.size()>k)pq.poll();}return pq.peek();}
    static int meetingRooms(int[][] ivs){Arrays.sort(ivs,(a,b)->a[0]-b[0]);PriorityQueue<Integer> pq=new PriorityQueue<>();for(int[] iv:ivs){if(!pq.isEmpty()&&pq.peek()<=iv[0])pq.poll();pq.offer(iv[1]);}return pq.size();}
    static int taskSched(char[] t,int n){int[] c=new int[26];for(char x:t)c[x-'A']++;int m=0;for(int x:c)m=Math.max(m,x);int cnt=0;for(int x:c)if(x==m)cnt++;return Math.max((m-1)*(n+1)+cnt,t.length);}
    public static void main(String[] a){
        System.out.println(kthLargest(new int[]{3,2,1,5,6,4},2));
        System.out.println(meetingRooms(new int[][]{{0,30},{5,10},{15,20}}));
        System.out.println(taskSched(new char[]{'A','A','A','B','B','B'},2));
        boolean ok=kthLargest(new int[]{3,2,1,5,6,4},2)==5&&meetingRooms(new int[][]{{0,30},{5,10},{15,20}})==2&&taskSched(new char[]{'A','A','A','B','B','B'},2)==8;
        System.out.println("All pass: "+ok);
    }
}

